private String wrap(String fragment)
{
    return "<?xml version=\"1.0\" encoding=\"UTF-8\"?><!DOCTYPE html>"
        + "<html xmlns=\"http://www.w3.org/1999/xhtml\"><head></head><body>" + fragment + "</body></html>";
}

private void removeTextWrappers(Node node)
{
    XPath xpath = XPathFactory.newInstance().newXPath();
    String expression = "//" + getInlineMarkerElementName() + "[@" + TEXT_WRAPPER + "]";
    try {
        XMLDiffUtils.asList((NodeList) xpath.compile(expression).evaluate(node, XPathConstants.NODESET)).stream()
            .forEach(this::replaceWithChildren);
    } catch (XPathExpressionException e) {
        // This shouldn't happen but in case it does the text wrappers shouldn't case any problems
    }
}

